/**
 * Notification model — core types for the notification system.
 *
 * Architecture: Event-driven via EventBus.
 * All notifications originate from AppEvents processed by the NotificationService,
 * which delegates delivery to NotificationAdapter implementations.
 *
 * Constraints:
 * - All adapters must implement the NotificationAdapter interface.
 * - All notifications must go through EventBus.emit() — never call adapters directly.
 * - Each NotificationChannel maps to exactly one adapter.
 */

/**
 * Supported notification channels.
 * Add new channels here when implementing new adapters.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app';

/**
 * Notification types that map to business events.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'welcome'
  | 'user-updated';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification ID */
  id: string;
  /** The type of notification (maps to a business event) */
  type: NotificationType;
  /** The channel this notification will be delivered through */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject / title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Additional metadata for adapter-specific behavior */
  metadata?: Record<string, unknown>;
  /** When the notification was created */
  createdAt: Date;
}

/**
 * Result returned by adapters after attempting delivery.
 */
export interface NotificationResult {
  /** Whether delivery succeeded */
  success: boolean;
  /** The notification that was sent */
  notificationId: string;
  /** The channel used for delivery */
  channel: NotificationChannel;
  /** Error message if delivery failed */
  error?: string;
  /** Timestamp of the delivery attempt */
  deliveredAt: Date;
}

/**
 * NotificationAdapter interface — the contract all notification delivery
 * channels must implement.
 *
 * Architecture: Event-driven via EventBus + Adapter pattern.
 * The NotificationService listens to EventBus events, builds NotificationPayloads,
 * and delegates delivery to the appropriate adapter based on channel.
 *
 * Constraints:
 * - Every adapter must implement this interface.
 * - Adapters handle delivery only — they must NOT subscribe to EventBus directly.
 * - The NotificationService is the sole coordinator between events and adapters.
 * - Adapters must be stateless with respect to notification routing logic.
 */

import type { NotificationPayload, NotificationResult, NotificationChannel } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must return a NotificationResult indicating success or failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails to an in-memory store
 * rather than sending real emails. Replace the send() internals with
 * a real email provider (SES, SendGrid, SMTP, etc.) for production use.
 *
 * Implements NotificationAdapter interface.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
  notificationId: string;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  /**
   * Send a notification via email.
   * Stub: stores the email in memory instead of sending.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
      notificationId: payload.id,
    };

    this.sentEmails.push(email);

    return {
      success: true,
      notificationId: payload.id,
      channel: this.channel,
      deliveredAt: email.sentAt,
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — coordinates notification delivery in response to events.
 *
 * Architecture: Event-driven via EventBus + Adapter pattern.
 * - Subscribes to EventBus events (the ONLY entry point for notifications).
 * - Transforms events into NotificationPayloads.
 * - Delegates delivery to registered NotificationAdapter implementations.
 *
 * Constraints:
 * - All notifications must originate from EventBus events.
 * - Never call adapters from outside this service.
 * - Each channel is handled by exactly one registered adapter.
 * - New notification channels are added by: (1) implementing NotificationAdapter,
 *   (2) registering the adapter via registerAdapter().
 *
 * Depends on:
 * - EventBus (event system) for receiving all events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private results: NotificationResult[] = [];

  constructor(private eventBus: EventBus) {
    this.subscribeToEvents();
  }

  /**
   * Register a notification adapter for a given channel.
   * Only one adapter per channel is allowed — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all relevant EventBus events.
   * This is the ONLY place where notification triggers are wired up.
   */
  private subscribeToEvents(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) =>
      this.handleOrderCreated(event),
    );

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) =>
      this.handleOrderStatusChanged(event),
    );

    this.eventBus.on<UserCreatedEvent>('user:created', (event) =>
      this.handleUserCreated(event),
    );
  }

  /**
   * Handle order created event — send confirmation email.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.sendNotification({
      type: 'order-status-update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  /**
   * Handle user created event — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.sendNotification({
      type: 'welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: `Welcome to TaskFlow Pro, ${event.user.name}!`,
      body: `Your account has been created. You can now start placing orders.`,
    });
  }

  /**
   * Build a NotificationPayload and deliver it via the appropriate adapter.
   */
  private async sendNotification(params: {
    type: NotificationPayload['type'];
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    metadata?: Record<string, unknown>;
  }): Promise<NotificationResult | undefined> {
    const adapter = this.adapters.get(params.channel);
    if (!adapter) {
      this.logger.warn(`No adapter registered for channel: ${params.channel}`);
      return undefined;
    }

    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      metadata: params.metadata,
      createdAt: new Date(),
    };

    this.logger.info(`Sending ${params.type} notification via ${params.channel} to ${params.recipient}`);

    const result = await adapter.send(payload);
    this.results.push(result);

    if (!result.success) {
      this.logger.error(`Notification delivery failed: ${result.error}`);
    }

    return result;
  }

  /**
   * Get all delivery results.
   */
  getResults(): NotificationResult[] {
    return [...this.results];
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.results.length;
  }

  /**
   * Clear all results (useful for testing).
   */
  clearResults(): void {
    this.results = [];
  }
}

